import { Component, HostBinding, Input, OnInit, Output } from '@angular/core';
import { Subject } from 'rxjs';

@Component({
  selector: 'app-input-fa',
  templateUrl: './input-fa.component.html',
  styleUrls: ['./input-fa.component.scss']
})
export class InputFaComponent implements OnInit {
  isFocus: boolean;
  @Input() icon: string;
  @Input() placeholder: string;
  @Output() value: Subject<string> = new Subject<string>();
  constructor() { }

  ngOnInit(): void {
  }

  @HostBinding('class.focus')
  get focus() {
    return this.isFocus;
  }

  emitValue(event: KeyboardEvent) {
    var value = (event.target as HTMLInputElement).value
    return this.value.next(value);
  }

}
