import { AfterViewInit, Component, OnInit } from '@angular/core';
import { MetadataShareService } from 'src/app/services/metadata-share.service';
import { SeoService } from 'src/app/services/seo.service';

@Component({
  selector: 'app-main',
  templateUrl: './main.component.html',
  styleUrls: ['./main.component.scss'],
})
export class MainComponent implements OnInit, AfterViewInit {
  constructor(
    private metadataShareService: MetadataShareService,
    private seoService: SeoService
  ) {}

  ngOnInit(): void {
    // meta data\
    let data: any = {
      seo: {
        title: 'MyComponents Page | Dynamic Title and Meta Tags Demo',
        metaTags: [
          { name: 'description', content: 'MyComponents description' },
          { property: 'og:title', content: 'MyComponents Title' },
          {
            proprety: 'og:description',
            content: 'MyComponents description',
          },
          { name: 'twitter:card', content: 'summary_large_image' },
        ],
      },
    };
    let seoData = data['seo'];
    this.seoService.updateTitle(seoData['title']);
    this.seoService.updateMetaTags(seoData['metaTags']);
  }

  ngAfterViewInit() {
    let b = document.createElement('button');
    b.innerText = 'OK';
    b.style.width = '100px';
    b.style.margin = '30px';
    b.onclick = () => alert('Hello!');
    document.getElementById('buttonWrapper').appendChild(b);
  }

  showInputValue(event: any) {
    console.log(event);
  }
}
